async (params, browser) => {
  // Open trending page
  await browser.open(`https://www.kaggle.com/${params.content_type}?sort=hotness`)

  // Wait for content to load
  await browser.waitForSelector('a[href*=\'/{{content_type}}/\'], a[href*=\'/code/\'], ul[role=\'list\']', 15000)

  // Let page render
  await browser.wait(3000)

  // Scroll for more items
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract trending items
  const page_data = await browser.evaluate(`const contentType = '' + params.content_type + ''; const items = []; const seen = new Set(); const linkPattern = contentType === 'code' ? /^\/code\/[^/]+\/[^/]+/ : contentType === 'datasets' ? /^\/datasets\/[^/]+\/[^/]+/ : /^\/competitions\/[^/]+$/; document.querySelectorAll('a[href]').forEach(a => { const href = a.getAttribute('href') || ''; if (seen.has(href) || !href.startsWith('/') || !linkPattern.test(href)) return; if (href.includes('/leaderboard') || href.includes('/discussion') || href.includes('/data') || href.includes('/rules')) return; const title = a.textContent.trim(); if (!title || title.length > 200 || title.length < 3) return; seen.add(href); const parent = a.closest('li') || a.parentElement; const desc = parent ? Array.from(parent.querySelectorAll('span,p')).map(e => e.textContent.trim()).filter(t => t.length > 20 && t !== title).slice(0, 1).join('') : ''; items.push({ title: title.substring(0, 200), url: 'https://www.kaggle.com' + href, description: desc.substring(0, 300) }); }); return { content_type: contentType, item_count: items.length, items: items.slice(0, 20), url: window.location.href };`)

  return page_data
}
